// ------------------------------
// Helpers dates
// ------------------------------
function parseIsoToDate(value) {
  if (!value || !window.gantt) return null;
  if (value instanceof Date) {
    return isNaN(+value) ? null : new Date(value.getFullYear(), value.getMonth(), value.getDate());
  }
  if (typeof value === "string") {
    const s = value.slice(0, 10);
    const parts = s.split("-");
    if (parts.length !== 3) return null;
    const y = Number(parts[0]);
    const m = Number(parts[1]);
    const d = Number(parts[2]);
    if (!y || !m || !d) return null;
    return new Date(y, m - 1, d);
  }
  return null;
}
function toIsoDate(value) {
  const d = parseIsoToDate(value);
  if (!d) return null;
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  return `${y}-${m}-${day}`;
}
function formatDateFr(isoStr) {
  if (!isoStr) return "";
  const s = String(isoStr).slice(0, 10);
  const [y, m, d] = s.split("-");
  if (!y || !m || !d) return s;
  return `${d}-${m}-${y}`;
}
function addDaysLocal(date, days) {
  const d = parseIsoToDate(date) || new Date(date);
  if (!d || isNaN(+d)) return null;
  const copy = new Date(d.getFullYear(), d.getMonth(), d.getDate());
  copy.setDate(copy.getDate() + days);
  return copy;
}

// Ramène une date au dernier jour ouvré si elle tombe le week-end
function normalizeToBusinessEnd(endIso) {
  const d = parseIsoToDate(endIso);
  if (!d) return null;
  const day = d.getDay(); // 0 dim, 6 sam
  if (day === 0) d.setDate(d.getDate() - 2);else if (day === 6) d.setDate(d.getDate() - 1);
  return toIsoDate(d);
}

// Ramène une date au prochain jour ouvré si elle tombe le week-end
function normalizeToBusinessStart(startIso) {
  const d = parseIsoToDate(startIso);
  if (!d) return null;
  const day = d.getDay();
  if (day === 6) d.setDate(d.getDate() + 2);else if (day === 0) d.setDate(d.getDate() + 1);
  return toIsoDate(d);
}

// Convertit end_date gantt (exclusive) -> date fin inclusive pour la base
function endExclusiveToInclusive(value) {
  const d = parseIsoToDate(value);
  if (!d) return null;
  d.setDate(d.getDate() - 1);
  return toIsoDate(d);
}

// Normalise les dates après drag
function normalizeDraggedTaskDates(task) {
  let startIso = toIsoDate(task.start_date);
  let endIso = endExclusiveToInclusive(task.end_date);
  startIso = normalizeToBusinessStart(startIso);
  endIso = normalizeToBusinessEnd(endIso);
  if (!startIso || !endIso) return null;
  const start = parseIsoToDate(startIso);
  const end = parseIsoToDate(endIso);
  if (!start || !end || end < start) return null;
  return {
    startIso,
    endIso
  };
}

// ------------------------------
// Helpers affichage / timeline
// ------------------------------
function computeTaskColumnWidth(tasks) {
  let maxChars = 10;
  (tasks || []).forEach(t => {
    const label = t.text || "";
    if (label.length > maxChars) maxChars = label.length;
  });
  return Math.min(maxChars * 7 + 40, 600);
}
function expandTimelineRangeFromTasks(tasks, marginDays = 90) {
  let minD = null;
  let maxEndD = null;
  (tasks || []).forEach(t => {
    const s = parseIsoToDate(t.start_date);
    let e = parseIsoToDate(t.end_date);
    if (e) {
      e = new Date(e);
      e.setDate(e.getDate() - 1); // end_date exclusive -> inclusive
    }
    if (s && (!minD || s < minD)) minD = s;
    if (e && (!maxEndD || e > maxEndD)) maxEndD = e;
  });
  if (!minD || !maxEndD) return;
  const start = new Date(minD);
  start.setDate(start.getDate() - marginDays);
  const end = new Date(maxEndD);
  end.setDate(end.getDate() + marginDays);
  gantt.config.start_date = start;
  gantt.config.end_date = end;
}
function getRowsSignature(rows) {
  try {
    return JSON.stringify((rows || []).map(r => ({
      numero_appareil: r.numero_appareil,
      groupe_appareil_id: r.groupe_appareil_id,
      date_debut: r.date_debut,
      date_fin: r.date_fin,
      delai: r.delai,
      statut_code: r.statut_code
    })));
  } catch (e) {
    return String(Date.now());
  }
}
function saveScrollState() {
  if (!window.ganttInitialized || !window.gantt || !gantt.getScrollState) return null;
  return gantt.getScrollState();
}
function restoreScrollState(state) {
  if (!state || !window.gantt || !gantt.scrollTo) return;
  gantt.scrollTo(state.x || 0, state.y || 0);
}

// ------------------------------
// Chargement Gantt
// ------------------------------
function ensureGanttLoaded() {
  if (window.gantt) return Promise.resolve();
  if (window.ganttLoading) return window.ganttLoading;
  window.ganttLoading = new Promise((resolve, reject) => {
    const script = document.createElement("script");
    script.src = "https://cdn.dhtmlx.com/gantt/edge/dhtmlxgantt.js";
    script.onload = () => resolve();
    script.onerror = reject;
    document.head.appendChild(script);
  });
  return window.ganttLoading;
}

// ------------------------------
// Zoom
// ------------------------------
function setScale(level) {
  if (!window.gantt) return;
  switch (level) {
    case "day":
      gantt.config.scales = [{
        unit: "month",
        step: 1,
        format: "%F %Y"
      }, {
        unit: "day",
        step: 1,
        format: "%d"
      }];
      break;
    case "month":
      gantt.config.scales = [{
        unit: "year",
        step: 1,
        format: "%Y"
      }, {
        unit: "month",
        step: 1,
        format: "%M"
      }];
      break;
    case "week":
    default:
      gantt.config.scales = [{
        unit: "year",
        step: 1,
        format: "%Y"
      }, {
        unit: "week",
        step: 1,
        format: date => "S" + gantt.date.date_to_str("%W")(date)
      }, {
        unit: "day",
        step: 1,
        format: "%d"
      }];
      break;
  }
  gantt.render();
}

// ------------------------------
// Marqueur aujourd'hui
// ------------------------------
function refreshTodayMarker() {
  if (!window.gantt || !gantt.addMarker) return;
  const today = new Date();
  if (window.todayMarkerId) gantt.deleteMarker(window.todayMarkerId);
  window.todayMarkerId = gantt.addMarker({
    start_date: today,
    css: "today-marker",
    text: "",
    title: ""
  });
  gantt.renderMarkers();
}
function centerOnToday(offsetRatio = 0.5) {
  if (!window.gantt) return;
  const today = new Date();
  const posX = gantt.posFromDate(today);
  const viewWidth = gantt.$task.offsetWidth;
  gantt.scrollTo(posX - Math.floor(viewWidth * offsetRatio), null);
}

// ------------------------------
// Mapping SQL -> Gantt
// ------------------------------
function mapRowsToGantt(rows) {
  const tasks = [];
  rows.forEach(r => {
    const startIsoRaw = r.date_debut ? String(r.date_debut).slice(0, 10) : null;
    const endIsoRaw = r.date_fin ? String(r.date_fin).slice(0, 10) : null;
    if (!startIsoRaw || !endIsoRaw) return;
    const startIso = normalizeToBusinessStart(startIsoRaw);
    const endIso = normalizeToBusinessEnd(endIsoRaw);
    if (!startIso || !endIso) return;
    const startDate = parseIsoToDate(startIso);
    const endDate = parseIsoToDate(endIso);
    if (!startDate || !endDate || endDate < startDate) return;
    const endExclusive = addDaysLocal(endIso, 1);
    tasks.push({
      id: String(r.numero_appareil),
      text: `${r.nom_appareil || ""}`,
      numero_appareil: r.numero_appareil,
      numero_affaire: r.numero_affaire,
      client: r.client,
      nom_appareil: r.nom_appareil,
      delai: r.delai ? String(r.delai).slice(0, 10) : null,
      groupe_appareil_id: r.groupe_appareil_id,
      groupe_code: r.groupe_code,
      statut_code: r.statut_code,
      statut_libelle: r.statut_libelle,
      statut_couleur: r.statut_couleur,
      start_date: startIso,
      end_date: toIsoDate(endExclusive),
      nombre_jours: r.fab_jours_base
    });
  });
  return {
    data: tasks,
    links: []
  };
}

// ------------------------------
// Tooltip
// ------------------------------
function enableTooltip() {
  gantt.templates.tooltip_text = function (start, end, task) {
    const endInclusive = endExclusiveToInclusive(end);
    return `
      <b>${task.text || ""}</b><br/>
      Client : ${task.client || ""}<br/>
      Début : ${formatDateFr(toIsoDate(start))}<br/>
      Fin : ${formatDateFr(endInclusive)}<br/>
      Délai : ${formatDateFr(task.delai)}<br/>
      Statut : ${task.statut_libelle || task.statut_code || ""}
    `;
  };
}

// ------------------------------
// Rendu
// ------------------------------
async function renderGantt() {
  if (window.isRenderingGantt) return;
  window.isRenderingGantt = true;
  try {
    const rows = appsmith.model && appsmith.model.rows || [];
    const rowsSignature = getRowsSignature(rows);

    // IMPORTANT : mémoriser la signature tout de suite
    // pour éviter qu'un onModelChange relance un 2e rendu pendant l'init
    if (!window.lastRowsSignature) {
      window.lastRowsSignature = rowsSignature;
    }
    await ensureGanttLoaded();
    const ganttData = mapRowsToGantt(Array.isArray(rows) ? rows : []);
    const idealWidth = computeTaskColumnWidth(ganttData.data);
    if (!window.ganttInitialized) {
      if (gantt.plugins) {
        gantt.plugins({
          marker: true,
          tooltip: true
        });
      }
      gantt.config.show_markers = true;
      gantt.config.readonly = false;
      gantt.config.drag_move = true;
      gantt.config.drag_resize = true;
      gantt.config.drag_progress = false;
      gantt.config.drag_links = false;
      gantt.config.details_on_dblclick = false;
      gantt.config.round_dnd_dates = true;
      gantt.config.show_links = false;
      gantt.config.date_format = "%Y-%m-%d";
      gantt.config.min_column_width = 30;
      gantt.config.grid_resize = true;
      gantt.config.row_height = 28;
      gantt.config.task_height = 10;
      gantt.config.work_time = true;
      gantt.config.skip_off_time = false;
      gantt.setWorkTime({
        day: 0,
        hours: false
      });
      gantt.setWorkTime({
        day: 6,
        hours: false
      });
      gantt.config.columns = [{
        name: "text",
        label: "Désignation",
        tree: false,
        width: idealWidth,
        min_width: 180
      }, {
        name: "delai",
        label: "Date obj.",
        align: "center",
        width: 100,
        template: task => formatDateFr(task.delai)
      }];
      const fmtIso = gantt.date.date_to_str("%Y-%m-%d");
      gantt.templates.scale_cell_class = function (date) {
        const day = date.getDay();
        const dStr = fmtIso(date);
        const todayStr = new Date().toISOString().slice(0, 10);
        const classes = [];
        if (day === 0 || day === 6) classes.push("weekend");
        if (dStr === todayStr) classes.push("today-scale");
        return classes.join(" ");
      };
      gantt.templates.timeline_cell_class = function (task, date) {
        const day = date.getDay();
        const dStr = fmtIso(date);
        const todayStr = new Date().toISOString().slice(0, 10);
        const classes = [];
        if (day === 0 || day === 6) classes.push("weekend");
        if (dStr === todayStr) classes.push("today-cell");
        return classes.join(" ");
      };
      gantt.templates.task_class = function (start, end, task) {
        const classes = ["fabrication-task"];
        if (task.statut_code) classes.push("status-" + task.statut_code);
        return classes.join(" ");
      };
      gantt.templates.grid_row_class = function () {
        return "fabrication-row";
      };
      gantt.templates.task_text = function () {
        return "";
      };
      enableTooltip();
      gantt.attachEvent("onBeforeTaskDrag", function (id, mode) {
        return mode === "move" || mode === "resize";
      });
      gantt.attachEvent("onAfterTaskDrag", function (id, mode) {
        try {
          const task = gantt.getTask(id);
          if (!task) {
            console.log("Drag ignoré : tâche introuvable", id);
            return true;
          }
          const normalized = normalizeDraggedTaskDates(task);
          if (!normalized) {
            console.log("Drag ignoré : dates invalides", {
              id,
              start_date: task.start_date,
              end_date: task.end_date
            });
            return true;
          }
          task.start_date = parseIsoToDate(normalized.startIso);
          task.end_date = addDaysLocal(normalized.endIso, 1);
          gantt.updateTask(id);
          const payload = {
            numero_appareil: task.numero_appareil,
            groupe_appareil_id: task.groupe_appareil_id,
            date_debut: normalized.startIso,
            date_fin: normalized.endIso,
            drag_mode: mode,
            ts: Date.now()
          };
          if (typeof appsmith.updateModel === "function") {
            appsmith.updateModel({
              ...appsmith.model,
              lastDragPayload: payload,
              lastDragTs: Date.now()
            });
          }
          if (typeof appsmith.triggerEvent === "function") {
            appsmith.triggerEvent("fabricationDatesChanged");
          }
        } catch (e) {
          console.error("Erreur onAfterTaskDrag", e);
        }
        return true;
      });
      gantt.attachEvent("onTaskDblClick", function () {
        return false;
      });
      gantt.init("gantt_here");
      window.ganttInitialized = true;
      setScale("week");
      const toolbar = document.querySelector(".planning-toolbar");
      if (toolbar && !window.toolbarBound) {
        toolbar.addEventListener("click", function (e) {
          const btn = e.target.closest("button[data-zoom]");
          if (!btn) return;
          setScale(btn.getAttribute("data-zoom"));
        });
        window.toolbarBound = true;
      }
    } else {
      if (gantt.config.columns && gantt.config.columns.length > 0) {
        gantt.config.columns[0].width = idealWidth;
      }
    }
    const previousScrollState = saveScrollState();
    gantt.clearAll();
    if (ganttData.data.length) {
      expandTimelineRangeFromTasks(ganttData.data, 90);
      gantt.parse(ganttData);
    }
    gantt.render();
    refreshTodayMarker();
    if (!window.hasInitialCenteredToday) {
      requestAnimationFrame(() => {
        requestAnimationFrame(() => {
          centerOnToday();
          window.hasInitialCenteredToday = true;
        });
