  } finally {
    window.isRenderingGantt = false;
  }
}

appsmith.onReady(renderGantt);

appsmith.onModelChange(() => {
  if (window.isRenderingGantt) return;

  const rows = (appsmith.model && appsmith.model.rows) || [];
